class Solution:
    def findGoodStrings(self, n, s1, s2, evil):
        MOD = 10**9 + 7
        # Build KMP failure function
        m = len(evil)
        fail = [0] * m
        j = 0
        for i in range(1, m):
            while j > 0 and evil[i] != evil[j]:
                j = fail[j-1]
            if evil[i] == evil[j]:
                j += 1
            fail[i] = j
        def kmp_next(state, ch):
            while state > 0 and ch != evil[state]:
                state = fail[state-1]
            if ch == evil[state]:
                state += 1
            return state
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(pos, kstate, tight_lo, tight_hi):
            if kstate == m:
                return 0
            if pos == n:
                return 1
            lo = s1[pos] if tight_lo else 'a'
            hi = s2[pos] if tight_hi else 'z'
            total = 0
            for c in map(chr, range(ord(lo), ord(hi)+1)):
                nk = kmp_next(kstate, c)
                if nk == m:
                    continue
                nl = tight_lo and c == lo
                nh = tight_hi and c == hi
                total += dp(pos+1, nk, nl, nh)
            return total % MOD
        return dp(0, 0, True, True)

