var findGoodStrings = function(n, s1, s2, evil) {
    const MOD = 1000000007n;
    const m = evil.length;
    const fail = new Array(m).fill(0);
    let j = 0;
    for (let i = 1; i < m; i++) {
        while (j > 0 && evil[i] !== evil[j]) j = fail[j-1];
        if (evil[i] === evil[j]) j++;
        fail[i] = j;
    }
    const transCache = new Map();
    function kmpNext(state, ch) {
        const key = state * 27 + ch.charCodeAt(0) - 97;
        if (transCache.has(key)) return transCache.get(key);
        let s = state;
        while (s > 0 && ch !== evil[s]) s = fail[s-1];
        if (ch === evil[s]) s++;
        transCache.set(key, s);
        return s;
    }
    const memo = new Map();
    function dp(pos, kstate, tightLo, tightHi) {
        if (kstate === m) return 0n;
        if (pos === n) return 1n;
        const key = pos * m * 4 + kstate * 4 + (tightLo ? 2 : 0) + (tightHi ? 1 : 0);
        if (memo.has(key)) return memo.get(key);
        const lo = tightLo ? s1[pos] : 'a';
        const hi = tightHi ? s2[pos] : 'z';
        let total = 0n;
        for (let c = lo.charCodeAt(0); c <= hi.charCodeAt(0); c++) {
            const ch = String.fromCharCode(c);
            const nk = kmpNext(kstate, ch);
            if (nk === m) continue;
            total += dp(pos+1, nk, tightLo && ch === lo, tightHi && ch === hi);
        }
        total %= MOD;
        memo.set(key, total);
        return total;
    }
    return Number(dp(0, 0, true, true));
};
